from selenium.webdriver.common.by import By
from selenium.webdriver.support.ui import WebDriverWait
from selenium.webdriver.support import expected_conditions as EC
from features.pages.base_page import BasePage
import os


class LoginPage(BasePage):
    """
    Login Page Object - handles all login page interactions.
    Extends BasePage for common browser actions.
    """

    # ── Locators ──────────────────────────────────────────────────────────
    # TODO: verify selectors against live app at 192.168.10.124:4001
    EMAIL_INPUT = (By.CSS_SELECTOR, "input[type='email'], input[name='email'], #email, input[placeholder*='Email' i]")
    PASSWORD_INPUT = (By.CSS_SELECTOR, "input[type='password'], input[name='password'], #password")
    LOGIN_BUTTON = (By.CSS_SELECTOR, "button[type='submit'], button:contains('Login'), input[type='submit']")
    REGISTER_LINK = (By.LINK_TEXT, "Register")
    ERROR_MESSAGE = (By.CSS_SELECTOR, "[role='alert'], .error-message, .alert-danger, .validation-error")
    SUCCESS_MESSAGE = (By.CSS_SELECTOR, ".success-message, .alert-success, [role='status']")
    PAGE_HEADING = (By.CSS_SELECTOR, "h1, h2")

    def __init__(self, driver):
        super().__init__(driver)
        self.base_url = os.getenv('BASE_URL', 'http://192.168.10.124:4001')

    # ── Navigation ────────────────────────────────────────────────────────

    def navigate_to_login(self):
        """Navigate to the login page."""
        self.open(self.base_url)
        self.wait_for_page_load()

    # ── Actions ───────────────────────────────────────────────────────────

    def enter_email(self, email):
        """Enter email into the email input field."""
        self.wait_and_fill(self.EMAIL_INPUT, email)

    def enter_password(self, password):
        """Enter password into the password input field."""
        self.wait_and_fill(self.PASSWORD_INPUT, password)

    def click_login_button(self):
        """Click the login button."""
        self.wait_and_click(self.LOGIN_BUTTON)
        self.wait_for_page_load()

    def login_with_credentials(self, email, password):
        """Complete login flow with provided credentials."""
        self.enter_email(email)
        self.enter_password(password)
        self.click_login_button()

    def login_with_role(self, role_name):
        """Login using credentials from test data for the given role."""
        creds = self.get_credentials_by_role(role_name)
        self.login_with_credentials(creds['username'], creds['password'])

    # ── Assertions ────────────────────────────────────────────────────────

    def verify_login_page_displayed(self):
        """Verify login page is displayed with expected elements."""
        assert self.is_element_visible(self.EMAIL_INPUT), "Email field not visible"
        assert self.is_element_visible(self.PASSWORD_INPUT), "Password field not visible"
        assert self.is_element_visible(self.LOGIN_BUTTON), "Login button not visible"
        assert self.is_element_visible(self.REGISTER_LINK), "Register link not visible"

    def verify_login_successful(self):
        """Verify user is logged in successfully."""
        # Wait for URL change or dashboard element
        WebDriverWait(self.driver, 10).until(
            lambda d: '/login' not in d.current_url.lower() or self.is_element_visible(self.SUCCESS_MESSAGE)
        )

    def verify_error_message_displayed(self):
        """Verify error message is displayed after failed login."""
        assert self.is_element_visible(self.ERROR_MESSAGE), "Error message not displayed"

    def verify_error_message_contains(self, expected_text):
        """Verify error message contains expected text."""
        error_text = self.get_element_text(self.ERROR_MESSAGE)
        assert expected_text.lower() in error_text.lower(), f"Expected '{expected_text}' not found in error message: {error_text}"

    def verify_username_accepted(self):
        """Verify username field accepted input."""
        value = self.get_element_attribute(self.EMAIL_INPUT, 'value')
        assert value, "Username field is empty after input"

    def verify_password_accepted(self):
        """Verify password field accepted input."""
        value = self.get_element_attribute(self.PASSWORD_INPUT, 'value')
        assert value, "Password field is empty after input"
